import { useCallback, useRef, useEffect } from 'react';

// Base64 encoded simple notification beep sound
const NOTIFICATION_SOUND_BASE64 = 'data:audio/mp3;base64,';

export const useNotificationSound = () => {
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Pre-load the audio
    audioRef.current = new Audio(NOTIFICATION_SOUND_BASE64);
    audioRef.current.volume = 0.7;
    
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  const playSound = useCallback(() => {
    if (audioRef.current) {
      // Reset and play
      audioRef.current.currentTime = 0;
      audioRef.current.play().catch((error) => {
        console.log('Could not play notification sound:', error);
      });
    }
  }, []);

  // More urgent double beep for new rides
  const playNewRideSound = useCallback(() => {
    if (audioRef.current) {
      audioRef.current.currentTime = 0;
      audioRef.current.play().then(() => {
        // Play again after short delay for emphasis
        setTimeout(() => {
          if (audioRef.current) {
            audioRef.current.currentTime = 0;
            audioRef.current.play().catch(() => {});
          }
        }, 300);
      }).catch((error) => {
        console.log('Could not play notification sound:', error);
      });
    }
  }, []);

  return { playSound, playNewRideSound };
};
